/**
 * Push notification handler for Edward PWA.
 *
 * This file is imported by the main service worker generated by next-pwa.
 * It handles push events and notification clicks.
 */

// Handle incoming push notifications
self.addEventListener('push', (event) => {
  if (!event.data) {
    console.log('Push event received but no data');
    return;
  }

  try {
    const data = event.data.json();

    const options = {
      body: data.body || '',
      icon: data.icon || '/icons/icon-192.png',
      badge: '/icons/icon-192.png',
      tag: data.tag || 'edward-notification',
      data: {
        url: data.url || '/',
      },
      // Vibrate pattern: vibrate 200ms, pause 100ms, vibrate 200ms
      vibrate: [200, 100, 200],
      // Keep notification visible until user interacts
      requireInteraction: false,
    };

    event.waitUntil(
      self.registration.showNotification(data.title || 'Edward', options)
    );
  } catch (error) {
    console.error('Error processing push notification:', error);
  }
});

// Handle notification click
self.addEventListener('notificationclick', (event) => {
  event.notification.close();

  const url = event.notification.data?.url || '/';

  // Focus existing window or open new one
  event.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true }).then((windowClients) => {
      // Check if there's already a window open
      for (const client of windowClients) {
        if (client.url.includes(self.location.origin) && 'focus' in client) {
          // Focus FIRST so iOS has time to resume the JS context,
          // then send the navigation message via postMessage + BroadcastChannel fallback.
          return client.focus().then(() => {
            const msg = { type: 'NOTIFICATION_CLICK', url: url };
            client.postMessage(msg);
            // BroadcastChannel as a durable fallback — survives even if
            // the main thread hasn't fully resumed after focus()
            try {
              const bc = new BroadcastChannel('edward-notification');
              bc.postMessage(msg);
              bc.close();
            } catch (_) { /* BroadcastChannel not available */ }
          });
        }
      }
      // No existing window, open a new one
      if (clients.openWindow) {
        // Also post to BroadcastChannel so the new window can pick it up
        try {
          const bc = new BroadcastChannel('edward-notification');
          bc.postMessage({ type: 'NOTIFICATION_CLICK', url: url });
          bc.close();
        } catch (_) { /* BroadcastChannel not available */ }
        return clients.openWindow(url);
      }
    })
  );
});

// Handle notification close (for analytics if needed)
self.addEventListener('notificationclose', (event) => {
  console.log('Notification closed:', event.notification.tag);
});

// Handle push subscription change (when browser refreshes subscription)
self.addEventListener('pushsubscriptionchange', (event) => {
  console.log('Push subscription changed, re-subscribing...');

  event.waitUntil(
    fetch('/api/push/vapid-key')
      .then((res) => res.json())
      .then((data) => {
        if (!data.vapid_public_key) throw new Error('No VAPID key from server');
        // Convert base64url VAPID key to Uint8Array
        const raw = atob(data.vapid_public_key.replace(/-/g, '+').replace(/_/g, '/'));
        const key = new Uint8Array(raw.length);
        for (let i = 0; i < raw.length; i++) key[i] = raw.charCodeAt(i);

        return self.registration.pushManager.subscribe({
          userVisibleOnly: true,
          applicationServerKey: key,
        });
      })
      .then((subscription) => {
        const key = subscription.getKey('p256dh');
        const auth = subscription.getKey('auth');
        return fetch('/api/push/subscribe', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            endpoint: subscription.endpoint,
            p256dh: btoa(String.fromCharCode(...new Uint8Array(key))),
            auth: btoa(String.fromCharCode(...new Uint8Array(auth))),
          }),
        });
      })
      .then(() => console.log('Re-subscribed to push notifications'))
      .catch((error) => console.error('Failed to re-subscribe:', error))
  );
});
